/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp).
    * Checks that the entire input is consumed. */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token next = in.peek();
    if (next != null) {
      throw new ParseException("Expected end of input but found " + next);
    }
    return result;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *            | let <def>+ in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token token = in.peek();
    if (token == null) throw new ParseException("Unexpected end of input");
    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();
    return parseBinaryExp();
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private AST parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token next = in.readToken();
    if (next != Lexer.THEN) throw new ParseException("Expected 'then' but found " + next);
    AST conseq = parseExp();
    next = in.readToken();
    if (next != Lexer.ELSE) throw new ParseException("Expected 'else' but found " + next);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp> */
  private AST parseLet() {
    in.readToken(); // consume 'let'
    ArrayList<Def> defs = new ArrayList<>();
    defs.add(parseDef());
    while (in.peek() != Lexer.IN) {
      if (in.peek() == null) throw new ParseException("Expected 'in' but found end of input");
      defs.add(parseDef());
    }
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: <id> := <exp> ; */
  private Def parseDef() {
    Token token = in.readToken();
    if (!(token instanceof Variable))
      throw new ParseException("Expected variable in definition but found " + token);
    Variable var = (Variable) token;
    Token bind = in.readToken();
    if (bind != Lexer.BIND)
      throw new ParseException("Expected ':=' but found " + bind);
    AST rhs = parseExp();
    Token semi = in.readToken();
    if (semi != SemiColon.ONLY)
      throw new ParseException("Expected ';' but found " + semi);
    return new Def(var, rhs);
  }

  /** Parses: map <id-list> to <exp> */
  private AST parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token next = in.readToken();
    if (next != Lexer.TO)
      throw new ParseException("Expected 'to' but found " + next);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: <id-list> ::= { <prop-id-list> }
    *          <prop-id-list> ::= <id> { , <id> }*
    */
  private Variable[] parseIdList() {
    Token token = in.peek();
    if (!(token instanceof Variable)) {
      return new Variable[0];
    }
    ArrayList<Variable> vars = new ArrayList<>();
    vars.add((Variable) in.readToken());
    while (in.peek() == Comma.ONLY) {
      in.readToken(); // consume ','
      Token next = in.readToken();
      if (!(next instanceof Variable))
        throw new ParseException("Expected variable after ',' but found " + next);
      vars.add((Variable) next);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: <term> { <binop> <term> }* (left associatively) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    Token token = in.peek();
    while (token instanceof OpToken && ((OpToken) token).isBinOp()) {
      OpToken opToken = (OpToken) in.readToken();
      BinOp op = opToken.toBinOp();
      AST right = parseTerm();
      left = new BinOpApp(op, left, right);
      token = in.peek();
    }
    return left;
  }

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }
    *            | empty | <int> | <bool>
    */
  private AST parseTerm() {
    Token token = in.peek();
    if (token == null) throw new ParseException("Unexpected end of input");

    // UnOp Term
    if (token instanceof OpToken && ((OpToken) token).isUnOp()) {
      OpToken opToken = (OpToken) in.readToken();
      UnOp op = opToken.toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    }

    // Empty
    if (token == EmptyConstant.ONLY) {
      in.readToken();
      return EmptyConstant.ONLY;
    }

    // Int
    if (token instanceof IntConstant) {
      return (IntConstant) in.readToken();
    }

    // Bool
    if (token instanceof BoolConstant) {
      return (BoolConstant) in.readToken();
    }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    token = in.peek();
    if (token == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' but found " + close);
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: <factor> ::= ( <exp> ) | <prim> | <id> */
  private AST parseFactor() {
    Token token = in.peek();
    if (token == null) throw new ParseException("Unexpected end of input");

    // ( Exp )
    if (token == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST exp = parseExp();
      Token close = in.readToken();
      if (close != RightParen.ONLY)
        throw new ParseException("Expected ')' but found " + close);
      return exp;
    }

    // Prim
    if (token instanceof PrimFun) {
      return (PrimFun) in.readToken();
    }

    // Id
    if (token instanceof Variable) {
      return (Variable) in.readToken();
    }

    throw new ParseException("Expected expression but found " + token);
  }

  /** Parses: <exp-list> ::= { <prop-exp-list> }
    *          <prop-exp-list> ::= <exp> { , <exp> }*
    */
  private AST[] parseExpList() {
    Token token = in.peek();
    if (token == RightParen.ONLY) {
      return new AST[0];
    }
    ArrayList<AST> exps = new ArrayList<>();
    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken(); // consume ','
      exps.add(parseExp());
    }
    return exps.toArray(new AST[0]);
  }
}

